#!/bin/bash
set -e
if echo dGVzdA== | base64 -D >/dev/null 2>&1; then B64FLAG="-D"; else B64FLAG="-d"; fi
mkdir -p components pages
echo 'Writing components/Nav.js...'
base64 $B64FLAG << 'B64_MARKER_1' > components/Nav.js

B64_MARKER_1
echo 'Writing components/Footer.js...'
base64 $B64FLAG << 'B64_MARKER_2' > components/Footer.js

B64_MARKER_2
echo 'Writing pages/index.js...'
base64 $B64FLAG << 'B64_MARKER_3' > pages/index.js

B64_MARKER_3
echo 'Writing pages/rooms.js...'
base64 $B64FLAG << 'B64_MARKER_4' > pages/rooms.js

B64_MARKER_4
echo 'Writing pages/about.js...'
base64 $B64FLAG << 'B64_MARKER_5' > pages/about.js

B64_MARKER_5
echo 'Writing pages/contact.js...'
base64 $B64FLAG << 'B64_MARKER_6' > pages/contact.js

B64_MARKER_6
echo 'Writing pages/booking.js...'
base64 $B64FLAG << 'B64_MARKER_7' > pages/booking.js

B64_MARKER_7
echo 'All 7 files written successfully.'
